            def __init__(self, code: str, display: str | None) -> None:
                self.code = code
                self.display = display

            def coding(self) -> Coding:
                """Returns a new `Coding` for this concept, with system ``https://www.medizininformatik-initiative.de/fhir/ext/modul-onko/CodeSystem/mii-cs-onko-weitere-klassifikationen-obds``."""
                return Coding(
                    system="https://www.medizininformatik-initiative.de/fhir/ext/modul-onko/CodeSystem/mii-cs-onko-weitere-klassifikationen-obds",
                    code=self.code,
                    display=self.display,
                )

            @classmethod
            def from_value(cls, code: str) -> Self:
                """Looks up the member whose ``code`` equals ``code``.

                Raises:
                    ValueError: if no member has that code.
                """
                for member in cls:
                    if member.code == code:
                        return member
                raise ValueError(f"Unknown code: {code}")

